findings.suggestion:
添加简单的内存速率限制器：
```javascript
var rateLimitMap = new Map(); // ip -> {count, resetTime}
function checkRateLimit(ip, maxReq, windowMs) {
  var now = Date.now();
  var entry = rateLimitMap.get(ip);
  if (!entry || now > entry.resetTime) {
    rateLimitMap.set(ip, {count: 1, resetTime: now + windowMs});
    return true;
  }
  if (entry.count >= maxReq) return false;
  entry.count++;
  return true;
}
// 在请求处理开始处
var clientIp = req.socket.remoteAddress;
if (!checkRateLimit(clientIp, 60, 60000)) {
  res.writeHead(429); res.end('Too Many Requests'); return;
}
```

